svg.script:
(function(){
var root=document.documentElement;
function q(sel){return Array.prototype.slice.call(root.querySelectorAll(sel));}
function toPoint(evt){var pt=root.createSVGPoint();pt.x=evt.clientX;pt.y=evt.clientY;return pt.matrixTransform(root.getScreenCTM().inverse());}
function restartAnimations(){var restarted=false;
 try{if(typeof root.pauseAnimations==='function') root.pauseAnimations();if(typeof root.setCurrentTime==='function'){root.setCurrentTime(0);restarted=true;}if(typeof root.unpauseAnimations==='function') root.unpauseAnimations();}catch(_err){}
 if(!restarted){q('animate,animateMotion').forEach(function(el){var parent=el.parentNode;var next=el.nextSibling;var clone=el.cloneNode(true);if(!parent) return;parent.removeChild(el);if(next) parent.insertBefore(clone,next);else parent.appendChild(clone);});}}
 q('[data-anim-action="replay"]').forEach(function(btn){btn.addEventListener('click',function(evt){restartAnimations();evt.preventDefault();});});
q('[data-draggable="overlay"]').forEach(function(box){
 var dragging=false, dx=0, dy=0;
 function boxX(){return parseFloat(box.getAttribute('data-x')||'0');}
 function boxY(){return parseFloat(box.getAttribute('data-y')||'0');}
 function baseClass(){return box.getAttribute('data-base-class')||'';}
 function setBox(x,y){box.setAttribute('data-x',x);box.setAttribute('data-y',y);box.setAttribute('transform','translate('+x+' '+y+')');}
 function startOverlayDrag(evt){var p=toPoint(evt);dragging=true;dx=p.x-boxX();dy=p.y-boxY();box.setAttribute('class',baseClass()+' dragging');evt.preventDefault();}
 function moveOverlayDrag(evt){if(!dragging) return;var p=toPoint(evt);setBox(p.x-dx,p.y-dy);evt.preventDefault();}
 function endOverlayDrag(){dragging=false;box.setAttribute('class',baseClass());}
 box.addEventListener('pointerdown',startOverlayDrag);
 root.addEventListener('pointermove',moveOverlayDrag);
 root.addEventListener('pointerup',endOverlayDrag);
 root.addEventListener('pointerleave',endOverlayDrag);
});
})();
